tables.schema_preview:
CREATE TABLE ark_seed_ledger(
  seedKey   TEXT PRIMARY KEY,
  kind      TEXT NOT NULL,
  title     TEXT NOT NULL,
  signature TEXT NOT NULL,
  body      TEXT NOT NULL,
  createdAt TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_ark_seed_ledger_kind ON ark_seed_ledger(kind);
CREATE INDEX idx_ark_seed_ledger_sig  ON ark_seed_ledger(signature);

CREATE TABLE artifact_manifest (
  id TEXT PRIMARY KEY,
  category TEXT NOT NULL,
  sha256 TEXT NOT NULL,
  size_bytes INTEGER NOT NULL,
  storage_tier TEXT NOT NULL,
  created_at TEXT NOT NULL
);
CREATE INDEX idx_artifact_sha
  ON artifact_manifest(sha256);
CREATE INDEX idx_artifact_manifest_sha256 ON artifact_manifest(sha256);

CREATE TABLE auth_approved_emails (
  email TEXT PRIMARY KEY,
  approvedAt TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS "auth_local_accounts" (
  email TEXT PRIMARY KEY,
  userId TEXT NOT NULL,
  passwordSalt TEXT NOT NULL,
  passwordHash TEXT NOT NULL,
  createdAt TEXT NOT NULL,
  updatedAt TEXT NOT NULL
);
CREATE UNIQUE INDEX idx_auth_local_accounts_userId
  ON auth_local_accounts(userId);

CREATE TABLE auth_sessions (
  sessionId TEXT PRIMARY KEY,
  userId TEXT NOT NULL,
  createdAt TEXT NOT NULL,
  expiresAt TEXT NOT NULL
);
CREATE INDEX idx_auth_sessions_userId ON auth_sessions(userId);

CREATE TABLE IF NOT EXISTS "auth_users" (
  userId TEXT PRIMARY KEY,
  email TEXT NOT NULL UNIQUE
);
CREATE UNIQUE INDEX idx_auth_users_email
  ON auth_users(email);

CREATE TABLE iroha_khs_alignment (
  alignId TEXT PRIMARY KEY,
  irohaUnitId TEXT NOT NULL,
  khsLawKey TEXT NOT NULL,
  relation TEXT NOT NULL,          -- SUPPORTS/REQUIRES/REFUTES/NONE
  score REAL NOT NULL DEFAULT 0,
  note TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT ''
);
CREATE INDEX idx_align_iroha ON iroha_khs_alignment(irohaUnitId);
CREATE INDEX idx_align_khs   ON iroha_khs_alignment(khsLawKey);

CREATE TABLE khs_concepts (
  conceptKey TEXT PRIMARY KEY,
  clusterKey TEXT NOT NULL,
  conceptLabel TEXT,
  conceptWeight INTEGER DEFAULT 1,
  createdAt TEXT NOT NULL,
  updatedAt TEXT NOT NULL
);
CREATE INDEX idx_khs_concepts_cluster
  ON khs_concepts(clusterKey);

CREATE TABLE khs_edges (
  edgeId     TEXT PRIMARY KEY,
  fromLawKey TEXT NOT NULL,
  toLawKey   TEXT NOT NULL,
  edgeType   TEXT NOT NULL,                      -- SUPPORTS|REFUTES|REQUIRES|DERIVES|EXPLAINS
  unitId     TEXT NOT NULL,
  status     TEXT NOT NULL DEFAULT 'proposed',    -- proposed|verified|rejected
  createdAt  TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_khs_edges_from ON khs_edges(fromLawKey);
CREATE INDEX idx_khs_edges_to   ON khs_edges(toLawKey);

CREATE TABLE khs_quality_flags (
  flagId    TEXT PRIMARY KEY,     -- deterministic
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  unitId    TEXT NOT NULL,
  flag      TEXT NOT NULL,         -- e.g. 'garbled_like'
  score     REAL NOT NULL DEFAULT 0,
  note      TEXT NOT NULL DEFAULT ''
);
CREATE INDEX idx_khs_quality_flags_unitId ON khs_quality_flags(unitId);
CREATE INDEX idx_khs_quality_flags_flag ON khs_quality_flags(flag);

CREATE TABLE khs_seed_clusters (
  clusterKey TEXT PRIMARY KEY,
  representativeSeed TEXT,
  clusterSize INTEGER,
  updatedAt TEXT
);
CREATE INDEX idx_khs_seed_clusters_size
ON khs_seed_clusters(clusterSize);

CREATE TABLE khs_units (
  unitId    TEXT PRIMARY KEY,
  doc       TEXT NOT NULL,
  pdfPage   INTEGER,
  quote     TEXT NOT NULL,
  quoteHash TEXT NOT NULL,
  locHint   TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_khs_units_doc     ON khs_units(doc);
CREATE INDEX idx_khs_units_pdfPage ON khs_units(pdfPage);

CREATE TABLE kokuzo_algorithms (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  threadId TEXT NOT NULL,
  title TEXT NOT NULL,
  steps TEXT NOT NULL, -- JSON array
  summary TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_kokuzo_algorithms_threadId ON kokuzo_algorithms(threadId);
CREATE INDEX idx_kokuzo_algorithms_createdAt ON kokuzo_algorithms(createdAt);

CREATE TABLE kokuzo_chunk_sources (
  chunk_id INTEGER PRIMARY KEY,
  evidence_id TEXT NOT NULL,         -- "KZPAGE:..."
  doc TEXT NOT NULL,
  pdfPage INTEGER NOT NULL
);
CREATE INDEX idx_chunk_sources_docpage ON kokuzo_chunk_sources(doc, pdfPage);

CREATE TABLE kokuzo_core (
  key TEXT PRIMARY KEY,
  summary TEXT NOT NULL,
  importance REAL NOT NULL,
  updated_at TEXT NOT NULL
);

CREATE TABLE kokuzo_files (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  filename TEXT NOT NULL,
  filepath TEXT NOT NULL UNIQUE,
  uploaded_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_kokuzo_files_uploaded_at
  ON kokuzo_files(uploaded_at);

CREATE TABLE kokuzo_glossary (
  term TEXT PRIMARY KEY,
  definition TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
, lang TEXT NOT NULL DEFAULT 'ja', source TEXT NOT NULL DEFAULT 'internal', notes TEXT NOT NULL DEFAULT '');
CREATE INDEX idx_kokuzo_glossary_term ON kokuzo_glossary(term);
CREATE INDEX idx_kokuzo_glossary_lang   ON kokuzo_glossary(lang);
CREATE INDEX idx_kokuzo_glossary_source ON kokuzo_glossary(so

CREATE TABLE kokuzo_glossary_v2 (
  term TEXT NOT NULL,
  lang TEXT NOT NULL,
  definition TEXT NOT NULL DEFAULT '',
  source TEXT NOT NULL DEFAULT 'internal',
  notes TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (term, lang)
);
CREATE INDEX idx_glossary_v2_term   ON kokuzo_glossary_v2(term);
CREATE INDEX idx_glossary_v2_lang   ON kokuzo_glossary_v2(lang);
CREATE INDEX idx_glossary_v2_source ON k

CREATE TABLE kokuzo_kanagi_cycle (
  seed_id TEXT PRIMARY KEY,
  kanagi_cycle_state TEXT NOT NULL DEFAULT 'L-IN_READY',
  last_cycle_at TEXT,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE INDEX idx_kanagi_cycle_state ON kokuzo_kanagi_cycle(kanagi_cycle_state, last_cycle_at);

CREATE TABLE kokuzo_learned_pages (
  id TEXT PRIMARY KEY,               -- "KZPAGE:<doc>:P<pdfPage>"
  doc TEXT NOT NULL,
  pdfPage INTEGER NOT NULL,
  learnedAt TEXT DEFAULT (datetime('now'))
);
CREATE INDEX idx_learned_doc_page ON kokuzo_learned_pages(doc, pdfPage);

CREATE TABLE kokuzo_page_links (
  from_doc  TEXT NOT NULL,
  to_doc    TEXT NOT NULL,
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY(from_doc, to_doc)
);
CREATE INDEX idx_kokuzo_page_links_from ON kokuzo_page_links(from_doc);
CREATE INDEX idx_kokuzo_page_links_to   ON kokuzo_page_links(to_doc);

CREATE TABLE kokuzo_pages (
  doc TEXT NOT NULL,
  pdfPage INTEGER NOT NULL,
  text TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now')), sha TEXT, kanagi_phase TEXT, cluster_id TEXT,
  PRIMARY KEY (doc, pdfPage)
);
CREATE INDEX idx_kokuzo_pages_doc ON kokuzo_pages(doc);
CREATE INDEX idx_kokuzo_pages_page ON kokuzo_pages(pdfPage);
CREATE TRIGGER kokuzo_pages_ai AFTER INSERT ON kokuzo_pages BEGIN
  INSERT INTO kokuzo_pa

CREATE VIRTUAL TABLE kokuzo_pages_fts USING fts5(
  text,
  doc UNINDEXED,
  pdfPage UNINDEXED,
  content='kokuzo_pages',
  content_rowid='rowid'
)
/* kokuzo_pages_fts(text,doc,pdfPage) */;

CREATE TABLE kokuzo_quantum_edges (
  id TEXT PRIMARY KEY,
  seed_a_id TEXT NOT NULL,
  seed_b_id TEXT NOT NULL,
  relation_type TEXT NOT NULL,       -- "SYNTHESIS" | "RESONANCE" | "CONFLICT"
  weight REAL NOT NULL DEFAULT 0.5,
  insight TEXT NOT NULL,
  created_at TEXT DEFAULT (datetime('now'))
);
CREATE INDEX idx_qe_a ON kokuzo_quantum_edges(seed_a_id);
CREATE INDEX idx_qe_b ON kokuzo_quantum_edges(seed_b_id);

CREATE TABLE kokuzo_recall_cache (
      thread_id TEXT PRIMARY KEY,
      center_claim TEXT NOT NULL DEFAULT '',
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    );

CREATE TABLE legacy_messages (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  thread_id TEXT NOT NULL,
  role TEXT NOT NULL,
  content TEXT NOT NULL,
  created_at INTEGER NOT NULL,
  sourceDb TEXT NOT NULL,
  importedAt TEXT NOT NULL
);
CREATE INDEX idx_legacy_messages_thread_id ON legacy_messages(thread_id);
CREATE INDEX idx_legacy_messages_created_at ON legacy_messages(created_at);

CREATE TABLE password_change_audit (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      userId TEXT NOT NULL,
      actionType TEXT NOT NULL,
      createdAt TEXT NOT NULL,
      ip TEXT,
      userAgent TEXT
    );
CREATE INDEX idx_pca_userId ON password_change_audit(userId);

CREATE TABLE password_reset_tokens (
      id TEXT PRIMARY KEY,
      userId TEXT NOT NULL,
      tokenHash TEXT NOT NULL,
      expiresAt TEXT NOT NULL,
      usedAt TEXT,
      createdAt TEXT NOT NULL,
      requesterIp TEXT,
      userAgent TEXT
    );
CREATE INDEX idx_prt_userId ON password_reset_tokens(userId);
CREATE INDEX idx_prt_tokenHash ON password_reset_tokens(tokenHash);

CREATE TABLE pwa_messages (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  threadId TEXT NOT NULL,
  role TEXT NOT NULL,
  content TEXT NOT NULL,
  createdAt TEXT,
  FOREIGN KEY(threadId) REFERENCES pwa_threads(threadId)
);
CREATE INDEX idx_pwa_messages_threadId ON pwa_messages(threadId);

CREATE TABLE pwa_threads (
  threadId TEXT PRIMARY KEY,
  title TEXT,
  updatedAt TEXT
);

CREATE TABLE session_memory (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  session_id TEXT NOT NULL,
  role TEXT NOT NULL CHECK(role IN ('user','assistant')),
  content TEXT NOT NULL,
  timestamp TEXT NOT NULL
);
CREATE INDEX idx_session_memory_session_time
  ON session_memory(session_id, timestamp);

CREATE TABLE synapse_log (
  synapseId TEXT PRIMARY KEY,
  createdAt TEXT NOT NULL,
  threadId TEXT NOT NULL,
  turnId TEXT NOT NULL,
  routeReason TEXT NOT NULL,
  lawTraceJson TEXT NOT NULL,
  heartJson TEXT NOT NULL,
  inputSig TEXT NOT NULL,
  outputSig TEXT NOT NULL,
  metaJson TEXT NOT NULL
);
CREATE INDEX idx_synapse_log_createdAt ON synapse_log(createdAt);
CREATE INDEX idx_synapse_log_threadId ON synapse_log(threadId);
CREATE INDEX idx_synapse_log_inputSig ON synapse_log(inputSig);

CREATE TABLE sync_events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  userId TEXT NOT NULL,
  deviceId TEXT,
  eventType TEXT NOT NULL,
  detailJson TEXT,
  createdAt TEXT NOT NULL
);
CREATE INDEX idx_sync_events_user ON sync_events(userId, createdAt);

CREATE TABLE tenmon_audit_log (
  id TEXT PRIMARY KEY,
  createdAt TEXT,
  question TEXT
);

CREATE TABLE tenmon_training_log (
  id TEXT PRIMARY KEY,
  createdAt TEXT,
  question TEXT
);

CREATE TABLE thread_persona_links (
  id TEXT PRIMARY KEY,
  thread_id TEXT NOT NULL,
  persona_id TEXT NOT NULL,
  link_mode TEXT NOT NULL DEFAULT 'fixed',
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_thread_persona_links_thread ON thread_persona_links(thread_id);

CREATE TABLE training_freezes (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  rules_snapshot TEXT NOT NULL, -- JSON
  created_at INTEGER NOT NULL
);
CREATE INDEX idx_training_freezes_created_at
  ON training_freezes(created_at);

CREATE TABLE training_messages (
  id TEXT PRIMARY KEY,
  session_id TEXT NOT NULL,
  role TEXT NOT NULL CHECK(role IN ('user', 'assistant', 'system')),
  content TEXT NOT NULL,
  created_at INTEGER NOT NULL,
  FOREIGN KEY (session_id) REFERENCES training_sessions(id) ON DELETE CASCADE
);
CREATE INDEX idx_training_messages_session_id
  ON training_messages(session_id);
CREATE INDEX idx_training_messages_created_at
  ON training_messages(created_at);

CREATE TABLE training_sessions (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  created_at INTEGER NOT NULL
);
CREATE INDEX idx_training_sessions_created_at
  ON training_sessions(created_at);

CREATE TABLE writer_artifacts (
  id TEXT PRIMARY KEY,
  runId TEXT NOT NULL,
  kind TEXT NOT NULL,
  content TEXT NOT NULL,
  proofJson TEXT NOT NULL DEFAULT '{}',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY(runId) REFERENCES writer_runs(id)
);
CREATE INDEX idx_writer_artifacts_runId ON writer_artifacts(runId);
CREATE INDEX idx_writer_artifacts_runId_createdAt
  ON writer_artifacts(runId, createdAt);

CREATE TABLE writer_runs (
  id TEXT PRIMARY KEY,
  threadId TEXT NOT NULL,
  mode TEXT,
  title TEXT,
  targetChars INTEGER,
  tolerancePct REAL,
  createdAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX idx_writer_runs_threadId ON writer_runs(threadId);
CREATE INDEX idx_writer_runs_threadId_createdAt
  ON writer_runs(threadId, createdAt);
